def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=np.float64)
    total_bins = len(bins)
    for i in range(total_bins):
        if bins[i] == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / bins[i]
        score = 0
        if ratio > 1.5:
            score = 2000 + 20 * (ratio - 1)**3
        elif ratio > 1:
            score = 1500 + 15 * (ratio - 1)**2
        else:
            if ratio > 0.9:
                score += 80 * ratio
            elif ratio > 0.7:
                score += 60 * ratio
            elif ratio > 0.4:
                score += 40 * ratio
            else:
                score += 20 * ratio
            if bins[i] < 5:
                score += 10
            elif bins[i] < 20:
                score += 5
            elif bins[i] > 150:
                score -= 10
            else:
                score -= 3 * (bins[i] / 100)
        if i % 3 == 0:
            score *= 1.2
        elif i % 3 == 1:
            score *= 0.95
        else:
            score *= 1.05
        neighborhood = []
        if i > 0:
            neighborhood.append(bins[i-1])
        if i < total_bins - 1:
            neighborhood.append(bins[i+1])
        if neighborhood:
            avg_nb = sum(neighborhood) / len(neighborhood)
            if avg_nb < 10:
                score += 7
            elif avg_nb > 100:
                score -= 7
        adjustment = 0
        for j in range(total_bins):
            if j != i:
                diff = abs(bins[j] - bins[i])
                if diff < 10:
                    adjustment -= 0.1 * (10 - diff)
                elif diff > 50:
                    adjustment += 0.05 * (diff - 50)
        priorities[i] = score + adjustment
    finite_priorities = priorities[np.isfinite(priorities)]
    min_priority = np.min(finite_priorities) if finite_priorities.size > 0 else 0
    for i in range(total_bins):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 200
    return priorities
